int test_calculation_reset(int a, int b, int c) {
    // 1. Create reactive variables for a, b, and c using reaction::var
    auto var_a = reaction::var(a);
    auto var_b = reaction::var(b);
    auto var_c = reaction::var(c);

    // 2. Create initial calculation that depends on a and b
    auto initial_calc = reaction::calc([](int x, int y) { return x + y; }, var_a, var_b);

    // 3. Reset the calculation to depend on b and c instead
    initial_calc.reset([](int x, int y) { return x * y; }, var_b, var_c);

    // 4. Return the result after reset
    return initial_calc.get();
}

