/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    using namespace reaction;

    // 1. Create a reactive variable for the sensor using reaction::var with initial value
    auto sensor = var(initialValue);

    // 2. Create two reactive variables to track recompute count and last processed value using reaction::var
    auto recomputeCount = var(0);
    auto lastProcessedValue = var(initialValue);

    // 3. Create a filter-triggered calculation using reaction::calc that:
    //    - Checks if the absolute difference between current and previous value exceeds the threshold
    //    - Updates the last processed value
    //    - Increments the recompute count
    //    - Returns a status string ("HIGH" or "NORMAL")
    auto statusCalc = calc([&]() -> std::string {
        double currentValue = sensor.get();
        double lastValue = lastProcessedValue.get();
        int currentCount = recomputeCount.get();

        // Check if the absolute difference exceeds threshold
        bool trigger = std::abs(currentValue - lastValue) > diffThreshold;

        if (trigger) {
            // Update last processed value
            lastProcessedValue.value(currentValue);
            // Increment recompute count
            recomputeCount.value(currentCount + 1);

            // Determine status based on level threshold
            if (currentValue > levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        }

        return currentValue > levelThreshold ? "HIGH" : "NORMAL";
    });

    // 4. Apply a filter to the calculation using the filter method with a lambda that implements the threshold logic
    statusCalc.filter([&](const std::string& status) -> bool {
        // The filter condition is already implemented in the calculation logic above
        // This filter simply allows the value to pass through since the actual filtering is done in the calc
        return true;
    });

    // 5. Update the sensor with the first value using the value method
    sensor.value(firstUpdate);

    // 6. Record the recompute count after the first update by calling the recompute count variable
    int firstCount = recomputeCount.get();

    // 7. Update the sensor with the second value using the value method
    sensor.value(secondUpdate);

    // 8. Record the recompute count after the second update by calling the recompute count variable
    int secondCount = recomputeCount.get();

    // 9. Get the final status by calling the calculation variable
    std::string finalStatus = statusCalc.get();

    // 10. Return a tuple containing the final status, first recompute count, and second recompute count
    return std::make_tuple(finalStatus, firstCount, secondCount);
}

}  // namespace test_reaction
```

