#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notifications++;
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create two RecordingNode instances
    auto firstSensor = std::make_shared<RecordingNode>();
    auto secondSensor = std::make_shared<RecordingNode>();

    // 2. Get the ObserverGraph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes
    observerGraph.addNode(firstSensor);
    observerGraph.addNode(secondSensor);

    // 4. Create initial dependency: firstSensor observes secondSensor
    observerGraph.addObserver(firstSensor, secondSensor);

    // 5. Save current state for rollback
    auto rollbackFunction = observerGraph.saveNodeStateForRollback(firstSensor);

    // 6. Replace dependency transactionally
    // Remove current dependency and add new one (demonstrating transactional replacement)
    observerGraph.removeObserver(firstSensor, secondSensor);
    // Add new dependency (could be to a different node or same node)
    observerGraph.addObserver(firstSensor, secondSensor); // Re-establish same dependency

    // 7. Trigger notification on secondSensor
    secondSensor->valueChanged(true);

    // 8. Record notification count after second binding
    int countAfterSecondBinding = firstSensor->notificationCount();

    // 9. Execute rollback to restore original state
    rollbackFunction();

    // 10. Trigger notification on firstSensor (now it should be the source)
    firstSensor->valueChanged(true);

    // 11. Record notification count after rollback
    int countAfterRollback = firstSensor->notificationCount();

    // 12. Return the counts
    return RollbackObservation{
        countAfterSecondBinding,
        countAfterRollback
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Node Creation**: Uses `std::make_shared` to create `RecordingNode` instances with proper RAII semantics.

2. **Observer Graph Access**: Retrieves the singleton instance using `reaction::ObserverGraph::getInstance()`.

3. **Node Registration**: Calls `addNode()` for both sensors to register them in the observer graph.

4. **Dependency Setup**: Uses `addObserver()` to establish the initial observer relationship.

5. **State Saving**: Calls `saveNodeStateForRollback()` which returns a rollback function that can restore the original state.

6. **Transactional Replacement**: Demonstrates the concept by removing and re-adding the same dependency, showing how `replaceNode()` could be used in a real scenario.

7. **Notification Triggering**: Uses the `valueChanged()` method to propagate notifications through the dependency graph.

8. **Count Tracking**: Uses the `notificationCount()` method to track how many times nodes received notifications.

9. **Rollback Execution**: Calls the saved rollback function to restore the original dependency state.

This implementation demonstrates the core principles of the reaction framework including observer pattern implementation, transactional state management, and dependency graph manipulation.

