```cpp
#pragma once

#include <reaction/reaction.h>
#include <unordered_set>
#include <functional>

namespace test_reaction {

class CacheProbeNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override;
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

CacheStatsSnapshot test_observer_cache_stats() {
    // 1. Create CacheProbeNode instances
    CacheProbeNode nodeA;
    CacheProbeNode nodeB;
    CacheProbeNode nodeC;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes with the graph
    graph.addNode(&nodeA);
    graph.addNode(&nodeB);
    graph.addNode(&nodeC);

    // 4. Set up direct observer relationship
    graph.addObserver(&nodeA, &nodeB);

    // 5. Set up transitive observer relationship
    graph.addObserver(&nodeB, &nodeC);

    // 6. Create NodeSet to store collected observers
    std::unordered_set<std::reference_wrapper<reaction::ObserverNode>, std::reference_wrapper_hash, std::reference_wrapper_equal> observers;

    // 7. Populate cache data by traversing the graph
    graph.collectObservers(&nodeA, observers);

    // 8. Get cache statistics before cleanup
    auto statsBefore = graph.getCacheStats();

    // 9. Trigger cache cleanup
    graph.triggerCacheCleanup();

    // 10. Get cache statistics after cleanup
    auto statsAfter = graph.getCacheStats();

    // 11. Close all nodes
    nodeA.close();
    nodeB.close();
    nodeC.close();

    // 12. Return cache stats snapshot
    return CacheStatsSnapshot{
        .graphEntriesBeforeCleanup = statsBefore.graphEntries,
        .graphEntriesAfterCleanup = statsAfter.graphEntries,
        .graphHitRatioAfterCleanup = statsAfter.hitRatio
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Node Creation**: Created three `CacheProbeNode` instances to demonstrate both direct and transitive relationships.

2. **Graph Registration**: Used `ObserverGraph::getInstance()` to get the singleton instance and registered all nodes using `addNode()`.

3. **Observer Relationships**: 
   - Direct: `nodeA` observes `nodeB`
   - Transitive: `nodeB` observes `nodeC`, making `nodeA` observe `nodeC` transitively

4. **NodeSet**: Used `std::unordered_set` with custom hash/equal functions for `std::reference_wrapper<ObserverNode>` as specified in the reference materials.

5. **Cache Statistics**: Extracted the required fields (`graphEntries` and `hitRatio`) from the `CacheStats` structure returned by `getCacheStats()`.

6. **Cleanup**: Called `close()` on all nodes to properly clean up resources.

7. **Return Value**: Constructed a `CacheStatsSnapshot` with the requested statistics before and after cache cleanup.

This implementation follows all the specified assessment objectives and correctly uses the `reaction` library functions as documented in the reference materials.

